import{_ as c,C as l,o as a,c as r,a3 as o,b as i,w as n,a as s,E as d,a4 as p}from"./chunks/framework.aYYe0dfI.js";const q=JSON.parse('{"title":"Namespace clore::net::openai","description":"The clore::net::openai namespace provides an asynchronous client for interacting with OpenAI-compatible language model APIs. It defines a set of non-blocking functions—call_completion_async, call_llm_async, and call_structured_async—that each accept a kota::event_loop reference and return an integer handle for tracking or cancelling the pending request. These functions abstract the details of HTTP communication and JSON serialization, allowing callers to submit prompts, system messages, model identifiers, and optional schema descriptors while offloading the asynchronous lifecycle management to the event loop.","frontmatter":{"title":"Namespace clore::net::openai","description":"The clore::net::openai namespace provides an asynchronous client for interacting with OpenAI-compatible language model APIs. It defines a set of non-blocking functions—call_completion_async, call_llm_async, and call_structured_async—that each accept a kota::event_loop reference and return an integer handle for tracking or cancelling the pending request. These functions abstract the details of HTTP communication and JSON serialization, allowing callers to submit prompts, system messages, model identifiers, and optional schema descriptors while offloading the asynchronous lifecycle management to the event loop.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/namespaces/clore/net/openai/index.md","filePath":"en/clore/namespaces/clore/net/openai/index.md"}'),h={name:"clore/namespaces/clore/net/openai/index.md"};function m(u,e,f,g,_,y){const t=l("Mermaid");return a(),r("div",null,[e[1]||(e[1]=o('<h1 id="namespace-clore-net-openai" tabindex="-1">Namespace <code>clore::net::openai</code> <a class="header-anchor" href="#namespace-clore-net-openai" aria-label="Permalink to &quot;Namespace `clore::net::openai`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>clore::net::openai</code> namespace provides an asynchronous client for interacting with <code>OpenAI</code>-compatible language model <code>APIs</code>. It defines a set of non-blocking functions—<code>call_completion_async</code>, <code>call_llm_async</code>, and <code>call_structured_async</code>—that each accept a <code>kota::event_loop</code> reference and return an integer handle for tracking or cancelling the pending request. These functions abstract the details of HTTP communication and JSON serialization, allowing callers to submit prompts, system messages, model identifiers, and optional schema descriptors while offloading the asynchronous lifecycle management to the event loop.</p><p>Architecturally, this namespace forms the <code>OpenAI</code> integration layer within the <code>clore::net</code> networking module. By centralizing the async request patterns and returning opaque handles, it decouples the application logic from the specifics of the <code>OpenAI</code> API, enabling consistent error handling, cancellation, and result dispatch through the event loop’s callback mechanism.</p><h2 id="diagram" tabindex="-1">Diagram <a class="header-anchor" href="#diagram" aria-label="Permalink to &quot;Diagram&quot;">​</a></h2>',5)),(a(),i(p,null,{default:n(()=>[d(t,{id:"mermaid-15",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20NS%5B%22openai%22%5D%0A%20%20%20%20NSC0%5B%22detail%22%5D%0A%20%20%20%20NS%20--%3E%20NSC0%0A%20%20%20%20NSC1%5B%22protocol%22%5D%0A%20%20%20%20NS%20--%3E%20NSC1%0A%20%20%20%20NSC2%5B%22schema%22%5D%0A%20%20%20%20NS%20--%3E%20NSC2%0A"})]),fallback:n(()=>[...e[0]||(e[0]=[s(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h2 id="subnamespaces" tabindex="-1">Subnamespaces <a class="header-anchor" href="#subnamespaces" aria-label="Permalink to &quot;Subnamespaces&quot;">​</a></h2><ul><li><a href="./detail/"><code>clore::net::openai::detail</code></a></li><li><a href="./protocol/"><code>clore::net::openai::protocol</code></a></li><li><a href="./schema/"><code>clore::net::openai::schema</code></a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-openai-call-completion-async" tabindex="-1"><code>clore::net::openai::call_completion_async</code> <a class="header-anchor" href="#clore-net-openai-call-completion-async" aria-label="Permalink to &quot;`clore::net::openai::call_completion_async`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:748</code></p><p>Definition: <code>network/openai.cppm:775</code></p><p>Implementation: <a href="./../../../../modules/openai/"><code>Module openai</code></a></p><p>Submits an asynchronous completion request to the <code>OpenAI</code> API, using an integer argument to identify a predefined prompt or configuration. The function accepts a reference to a <code>kota::event_loop</code> for managing the asynchronous lifecycle; the caller must ensure the loop remains active until the request completes.</p><p>Returns an integer handle that uniquely identifies the pending request. This handle can later be used to monitor or cancel the operation. The caller is responsible for providing a valid event loop and for handling the result through the loop&#39;s event dispatch mechanism.</p><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called with a <code>CompletionRequest</code> and an event loop reference</li><li>typically <code>co_await</code>ed within another coroutine</li></ul><h3 id="clore-net-openai-call-llm-async" tabindex="-1"><code>clore::net::openai::call_llm_async</code> <a class="header-anchor" href="#clore-net-openai-call-llm-async" aria-label="Permalink to &quot;`clore::net::openai::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:752</code></p><p>Definition: <code>network/openai.cppm:782</code></p><p>Implementation: <a href="./../../../../modules/openai/"><code>Module openai</code></a></p><p>Initiates an asynchronous request to a large language model, sending the provided prompt and system message as parameters along with an integer argument (such as a token limit or temperature). The function returns an integer identifier that can be used to track or cancel the pending request. The caller must supply an active <code>kota::event_loop</code> reference; the asynchronous result is delivered through the event loop&#39;s callback mechanism.</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called with a model name, system prompt, integer parameter, and event loop to start an async LLM call</li><li>Used to submit a request to an LLM endpoint asynchronously</li></ul><h3 id="clore-net-openai-call-llm-async-1" tabindex="-1"><code>clore::net::openai::call_llm_async</code> <a class="header-anchor" href="#clore-net-openai-call-llm-async-1" aria-label="Permalink to &quot;`clore::net::openai::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:758</code></p><p>Definition: <code>network/openai.cppm:793</code></p><p>Implementation: <a href="./../../../../modules/openai/"><code>Module openai</code></a></p><p>The function <code>clore::net::openai::call_llm_async</code> initiates an asynchronous request to an <code>OpenAI</code>-compatible language model. It accepts three <code>std::string_view</code> parameters (commonly a model identifier, a user prompt, and a system message) and a reference to a <code>kota::event_loop</code>. The caller must ensure that the event loop is running and that the passed string views remain valid for the duration of the operation. The function returns an <code>int</code> that serves as a handle for the request (e.g., a request ID or error indicator), allowing the caller to track or cancel the operation.</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to invoke large language models asynchronously in a coroutine context</li><li>Commonly called from other async functions that compose LLM calls</li></ul><h3 id="clore-net-openai-call-structured-async" tabindex="-1"><code>clore::net::openai::call_structured_async</code> <a class="header-anchor" href="#clore-net-openai-call-structured-async" aria-label="Permalink to &quot;`clore::net::openai::call_structured_async`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:765</code></p><p>Definition: <code>network/openai.cppm:805</code></p><p>Implementation: <a href="./../../../../modules/openai/"><code>Module openai</code></a></p><p><code>clore::net::openai::call_structured_async</code> is a template function that initiates an asynchronous request to the <code>OpenAI</code> API to obtain a structured response of the type specified by the template parameter <code>T</code>. The caller supplies three <code>std::string_view</code> arguments — typically representing a system prompt, a user message, and an output schema or format descriptor — along with a reference to a <code>kota::event_loop</code> for driving the async operation. The function returns an <code>int</code>, which may serve as a request identifier or status code for subsequent cancellation or completion tracking.</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to obtain structured outputs from an <code>OpenAI</code> language model in an asynchronous context</li><li>Called from other coroutines that require structured data from LLM completions</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore::net</a></li><li><a href="./detail/">Namespace clore::net::openai::detail</a></li><li><a href="./protocol/">Namespace clore::net::openai::protocol</a></li><li><a href="./schema/">Namespace clore::net::openai::schema</a></li></ul>',34))])}const k=c(h,[["render",m]]);export{q as __pageData,k as default};
